// Caterbook report format (from benchmark fixtures):
//   Caterbook Daily Report 2026-05-08
//   Occupancy 78%
//   Rooms occupied: 7 of 9
//   ADR £92.50
//   RevPAR £72.15
//   Room revenue £647.50

const body = ($json.body_text || '').replace(/\r/g, '');

function money(label) {
  const re = new RegExp(label + '\\s*[:\\s]?\\s*\u00a3?\\s*([\\d,]+(?:\\.\\d{1,2})?)', 'i');
  const m = body.match(re);
  return m ? parseFloat(m[1].replace(/,/g, '')) : null;
}

let reportDate = null;
// ISO format first
const iso = body.match(/(\d{4}-\d{2}-\d{2})/);
if (iso) reportDate = iso[1];
else {
  // UK format
  const uk = body.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/);
  if (uk) reportDate = `${uk[3]}-${uk[2].padStart(2,'0')}-${uk[1].padStart(2,'0')}`;
}

const occMatch  = body.match(/Occupancy\s*[:\s]?\s*(\d+(?:\.\d+)?)\s*%/i);
const occupancy = occMatch ? parseFloat(occMatch[1]) : null;

const roomMatch = body.match(/(\d+)\s*(?:of|\/)\s*(\d+)/i) || body.match(/Rooms?\s*occupied[:\s]+(\d+)\s*(?:of|\/)\s*(\d+)/i);
let roomsOccupied = null, totalRooms = null;
if (roomMatch) { roomsOccupied = parseInt(roomMatch[1], 10); totalRooms = parseInt(roomMatch[2], 10); }

const adr     = money('ADR');
const revpar  = money('RevPAR');
const revenue = money('Room\\s+revenue');

const parseable = !!(reportDate && occupancy !== null);

return { json: {
  email_id:       $json.email_id,
  report_date:    reportDate,
  occupancy_pct:  occupancy,
  rooms_occupied: roomsOccupied,
  total_rooms:    totalRooms,
  adr:            adr,
  revpar:         revpar,
  room_revenue:   revenue,
  raw_text:       body.substring(0, 2000),
  parseable:      parseable,
  from_address:   $json.from_address,
  subject:        $json.subject,
} };
